message = "Top Secret";

// Generate AES secret key
secretKey = generateSecretKey("AES", 256);

// Encrypt the message
encryptedText = encrypt(message, secretKey, "AES", "Base64");

// Decrypt the message
decryptedText = decrypt(encryptedText, secretKey, "AES", "Base64");

writeDump({
    encrypted = encryptedText,
    decrypted = decryptedText
});
